  const mencionaCitaOHora =
    /\b(?:hora|horas|horario|horarios|cita|citas|turno|turnos|cupo|cupos|disponibilidad|disponible)\b/.test(
      texto
    );

  const solicitudDirecta =
    /\b(?:quiero|quisiera|necesito|deseo|busco|me gustaria|puedo|podria)\b/.test(
      texto
    );

  const mencionaFecha =
    /\b(?:hoy|manana|pasado manana|esta semana|la proxima semana|lunes|martes|miercoles|jueves|viernes|sabado|domingo)\b/.test(
      texto
    ) ||
    /\b\d{1,2}\s+de\s+(?:enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|setiembre|octubre|noviembre|diciembre)\b/.test(
      texto
    );

  const preguntaSoloInformativa =
    /\b(?:cuanto cuesta|cuanto sale|precio|precios|que servicios|que incluye|ofrecen peluqueria)\b/.test(
      texto
    );

  if (
    preguntaSoloInformativa &&
    !preguntaDisponibilidad &&
    !accionAgenda &&
    !mencionaCitaOHora
  ) {
    return false;
  }

  return (
    preguntaDisponibilidad ||
    accionAgenda ||
    mencionaCitaOHora ||
    (solicitudDirecta && mencionaPeluqueria) ||
    (mencionaPeluqueria && mencionaFecha)
  );
})() }}

