={{ (() => {
  const texto = String(
    $json.body?.chatInput ||
    $json.chatInput ||
    $json.body?.mensajeActual ||
    $json.mensajeActual ||
    $json.body?.mensaje ||
    $json.mensajeCliente ||
    ""
  );

  const normalizar = (valor) =>
    String(valor || "")
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .trim();

  const palabrasCorte = new Set([
    "esta",
    "este",
    "semana",
    "hoy",
    "mañana",
    "manana",
    "pasado",
    "el",
    "la",
    "los",
    "las",
    "y",
    "con",
    "para",
    "de",
    "del",
    "que",
    "porque",
    "pero",
    "mi",
    "su",
    "es",
    "tiene",
    "necesita",
    "quiero"
  ]);

  const palabrasNoValidasComoNombre = new Set([
    "peluqueria",
    "lavado",
    "bano",
    "baño",
    "corte",
    "servicio",
    "servicios",
    "hora",
    "horas",
    "horario",
    "horarios",
    "cita",
    "citas",
    "disponibilidad",
    "disponible",
    "semana",
    "manana",
    "mañana",
    "hoy",
    "perro",
    "perra",
    "gato",
    "gata",
    "mascota"
  ]);

  const limpiarNombre = (valor) => {
    const palabras = String(valor || "")
      .trim()
      .split(/\s+/);

    const nombre = [];

    for (const palabraOriginal of palabras) {
      const palabraLimpia = palabraOriginal
        .replace(/^[¿¡"'()]+/g, "")
        .replace(/[.,;!?"'()]+$/g, "");

      const palabraNormalizada = normalizar(
        palabraLimpia
      );

      if (
        !palabraLimpia ||
        palabrasCorte.has(palabraNormalizada)
      ) {
        break;
      }

      nombre.push(palabraLimpia);

      if (nombre.length >= 3) {
        break;
      }
    }

    return nombre.join(" ").trim();
  };

  const esNombreValido = (valor) => {
    const nombre = limpiarNombre(valor);

    if (!nombre) {
      return false;
    }

    const primeraPalabra = normalizar(
      nombre.split(/\s+/)[0]
    );

    if (
      palabrasNoValidasComoNombre.has(
        primeraPalabra
      )
    ) {
      return false;
    }

    return /^[A-Za-zÁÉÍÓÚÜÑáéíóúüñ'-]+(?:\s+[A-Za-zÁÉÍÓÚÜÑáéíóúüñ'-]+){0,2}$/.test(
      nombre
    );
  };

  const patronesDirectos = [
    /\bmascota\s*:\s*([^.,;!?\n]+)/i,

    /\b(?:mi|la)\s+mascota\s+(?:es|se llama)\s+([^.,;!?\n]+)/i,

    /\b(?:mi\s+)?(?:perro|perra|perrito|perrita|cachorro|cachorra|gato|gata|gatito|gatita)\s+se llama\s+([^.,;!?\n]+)/i,

    /\b(?:mi\s+)?(?:perro|perra|perrito|perrita|cachorro|cachorra|gato|gata|gatito|gatita)\s+([^.,;!?\n]+)/i
  ];

  for (const patron of patronesDirectos) {
    const coincidencia = texto.match(patron);

    if (coincidencia?.[1]) {
      const nombre = limpiarNombre(
        coincidencia[1]
      );

      if (esNombreValido(nombre)) {
        return nombre;
      }
    }
  }

  /*
   * Caso: "una hora para Toby".
   * Se evalúa al final para evitar interpretar
   * "para peluquería" o "para baño y corte"
   * como nombre de mascota.
   */
  const coincidenciaPara = texto.match(
    /\bpara\s+([A-Za-zÁÉÍÓÚÜÑáéíóúüñ'-]+(?:\s+[A-Za-zÁÉÍÓÚÜÑáéíóúüñ'-]+){0,2})(?=\s*(?:[.,;!?\n]|$))/i
  );

  if (coincidenciaPara?.[1]) {
    const nombre = limpiarNombre(
      coincidenciaPara[1]
    );

    if (esNombreValido(nombre)) {
      return nombre;
    }
  }

  const nombreExistente = String(
    $json.body?.nombreMascota ||
    $json.nombreMascota ||
    ""
  ).trim();

  return esNombreValido(nombreExistente)
    ? limpiarNombre(nombreExistente)
    : "";
})() }}

={{ (() => {
  const texto = String(
    $json.body?.chatInput ||
