  );

  const coincidencia = texto.match(/(?:\+?56\s*)?9?\s*\d{4}\s*\d{4}/);

  if (!coincidencia) return "";

  let digitos = coincidencia[0].replace(/\D/g, "");

  if (digitos.startsWith("56")) {
    digitos = digitos.slice(2);
  }

  if (digitos.length === 8) {
    digitos = "9" + digitos;
  }

  if (digitos.length === 9) {
    return `+56 ${digitos.slice(0, 1)} ${digitos.slice(1, 5)} ${digitos.slice(5)}`;
  }

  return coincidencia[0].trim();
})() }}

