={{ (() => {
  const webhook = $("Webhook Solicitud Agenda").first().json;

  const mensajeActual = String(
    webhook.body?.mensajeActual ||
    webhook.mensajeActual ||
    webhook.body?.mensaje ||
    webhook.mensaje ||
    ""
  ).trim();

  const normalizarTexto = (valor) =>
    String(valor || "")
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/[“”"]/g, "")
      .trim();

  const texto = normalizarTexto(
    mensajeActual
  );

  if (!texto) {
    return false;
  }

  /*
   * Selección mediante número:
   * 2
   * opción 2
   * alternativa 2
   */
  const seleccionNumerica =
    /^[1-3][.!]?$/.test(texto) ||
    /\b(?:opcion|alternativa)\s*(?:numero\s*)?[1-3]\b/.test(texto);

  if (seleccionNumerica) {
    return true;
  }

  /*
   * Selección mediante una frase:
   * Elijo la opción 2
   * Prefiero la segunda
   * Selecciono la alternativa dos
   */
  const seleccionPorFrase =
    /\b(?:elijo|escojo|selecciono|prefiero|quiero)\s+(?:la\s+)?(?:opcion|alternativa)?\s*(?:[1-3]|uno|una|dos|tres|primera|primero|segunda|segundo|tercera|tercero)\b/.test(
      texto
    ) ||
    /^(?:la\s+)?(?:primera|primero|segunda|segundo|tercera|tercero)[.!]?$/.test(
      texto
    );

  if (seleccionPorFrase) {
    return true;
  }

  /*
   * Selección mediante fecha:
   * martes 14 de julio, de 11:00 a 13:00
   * 14 de julio a las 11:00
   * mañana a las 11:00
   */
  const tieneFechaExplicita =
    /\b\d{1,2}\s+de\s+(?:enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|setiembre|octubre|noviembre|diciembre)(?:\s+de\s+\d{4})?\b/.test(
      texto
    );

  const tieneFechaRelativa =
    /\b(?:hoy|manana|pasado manana|lunes|martes|miercoles|jueves|viernes|sabado|domingo)\b/.test(
      texto
    );

  const tieneRangoHorario =
    /\bde\s+\d{1,2}(?::\d{2})?\s+a\s+\d{1,2}(?::\d{2})?\b/.test(
      texto
    );

  const tieneHoraInicio =
    /\b(?:a\s+las\s+|desde\s+las\s+|de\s+)\d{1,2}(?::\d{2})?\s*(?:de\s+la\s+)?(?:manana|tarde|noche)?\b/.test(
      texto
    );

  return (
    (tieneFechaExplicita || tieneFechaRelativa) &&
    (tieneRangoHorario || tieneHoraInicio)
  );
})() }}

