  };

  const ahora = $now.setZone(TIMEZONE);

  function obtenerNumeroOpcion(texto) {
    const normalizado = normalizarTexto(texto);

    if (/^[1-3]$/.test(normalizado)) {
      return Number(normalizado);
    }

    const opcionNumerica =
      normalizado.match(
        /\b(?:elijo|escojo|selecciono|prefiero)\s+(?:la\s+)?(?:opcion|alternativa)?\s*([1-3])\b/
      ) ||
      normalizado.match(
        /\b(?:opcion|alternativa)\s*(?:numero\s*)?([1-3])\b/
      );

    if (opcionNumerica?.[1]) {
      return Number(opcionNumerica[1]);
    }

    const opcionTexto =
      normalizado.match(
        /\b(?:elijo|escojo|selecciono|prefiero)\s+(?:la\s+)?(?:opcion|alternativa)?\s*(primera|primero|segunda|segundo|tercera|tercero|uno|una|dos|tres)\b/
      ) ||
      normalizado.match(
        /\b(?:opcion|alternativa)\s+(uno|una|dos|tres|primera|primero|segunda|segundo|tercera|tercero)\b/
      ) ||
      normalizado.match(
        /^\s*(?:la\s+)?(primera|primero|segunda|segundo|tercera|tercero)\s*$/
      );

    if (opcionTexto?.[1]) {
      return numerosTexto[opcionTexto[1]] || null;
