      if (coincidencia?.[1]) {
        lineaEncontrada = coincidencia[1].trim();
      }
    }

    return lineaEncontrada;
  }

  function construirInicioDesdeOpcion(linea) {
    const texto = normalizarTexto(linea);

    const coincidencia = texto.match(
      /\b(\d{1,2})\s+de\s+([a-z]+)(?:\s+de\s+(\d{4}))?.*?\bde\s+(\d{1,2})(?::(\d{2}))?\s+a\s+(\d{1,2})(?::(\d{2}))?\b/
