    const minuto = Number(coincidencia[5] || 0);

    if (!mes) {
      return "";
    }

    let inicio = ahora.set({
      year: anioExplicito || ahora.year,
      month: mes,
      day: dia,
      hour: hora,
      minute: minuto,
      second: 0,
      millisecond: 0
    });

    if (
      !anioExplicito &&
      inicio < ahora.startOf("day")
    ) {
      inicio = inicio.plus({ years: 1 });
    }

    return inicio.isValid
      ? inicio.toISO()
      : "";
  }

  function construirInicioDesdeTexto(textoOriginal) {
    const texto = normalizarTexto(textoOriginal);

    let anio = ahora.year;
    let mes = ahora.month;
    let dia = ahora.day;
    let tieneFechaExplicita = false;

    const fechaExplicita = texto.match(
      /\b(\d{1,2})\s+de\s+([a-z]+)(?:\s+de\s+(\d{4}))?\b/
    );

    if (fechaExplicita) {
      dia = Number(fechaExplicita[1]);
      mes = meses[fechaExplicita[2]];

      if (!mes) {
        return "";
      }

      anio = fechaExplicita[3]
        ? Number(fechaExplicita[3])
        : ahora.year;

      tieneFechaExplicita = true;
    } else if (texto.includes("pasado manana")) {
      const fecha = ahora.plus({ days: 2 });
      anio = fecha.year;
      mes = fecha.month;
      dia = fecha.day;
    } else if (texto.includes("manana")) {
      const fecha = ahora.plus({ days: 1 });
      anio = fecha.year;
      mes = fecha.month;
      dia = fecha.day;
    } else if (texto.includes("hoy")) {
      anio = ahora.year;
      mes = ahora.month;
      dia = ahora.day;
    }

    const horaEncontrada =
      texto.match(
        /\b(?:a\s+las\s+|desde\s+las\s+|de\s+)(\d{1,2})(?::(\d{2}))?\s*(?:de\s+la\s+)?(manana|tarde|noche)?\b/
      ) ||
      texto.match(
        /\b(\d{1,2})(?::(\d{2}))\s*(?:de\s+la\s+)?(manana|tarde|noche)?\b/
      );

    if (!horaEncontrada) {
      return "";
    }

    let hora = Number(horaEncontrada[1]);
    const minuto = Number(horaEncontrada[2] || 0);
    const periodo = horaEncontrada[3] || "";

    if (
      (periodo === "tarde" ||
        periodo === "noche") &&
      hora < 12
    ) {
      hora += 12;
    }

    if (
      periodo === "manana" &&
      hora === 12
    ) {
      hora = 0;
    }

    if (
      !periodo &&
      hora >= 1 &&
      hora <= 6
    ) {
      hora += 12;
    }

    let inicio = ahora.set({
      year: anio,
      month: mes,
      day: dia,
      hour: hora,
      minute: minuto,
      second: 0,
      millisecond: 0
    });

    if (
      tieneFechaExplicita &&
      !fechaExplicita?.[3] &&
      inicio < ahora.startOf("day")
    ) {
      inicio = inicio.plus({ years: 1 });
    }

    return inicio.isValid
      ? inicio.toISO()
      : "";
  }

  const numeroOpcion =
    obtenerNumeroOpcion(mensajeActual);

  if (numeroOpcion) {
    const lineaOpcion =
      obtenerLineaOpcion(numeroOpcion);

    const inicioOpcion =
      construirInicioDesdeOpcion(
        lineaOpcion
      );

    if (inicioOpcion) {
      return inicioOpcion;
    }
  }

  return construirInicioDesdeTexto(
    mensajeActual
  );
})() }}

