={{ (() => {
  const datos = $("Preparar Datos Peluquería").first().json;
  const horario = $("Preparar Horario Seleccionado Peluquería").first().json;

  const nombresServicios = {
    "baño_sanitario": "servicio de baño",
    "baño_y_corte": "servicio de baño y corte",
    "corte_de_pelo": "servicio de corte de pelo",
    "peluqueria": "servicio de peluquería"
  };

  const servicioVisible =
    nombresServicios[datos.servicioSolicitado] ||
    String(datos.servicioSolicitado || "peluquería").replaceAll("_", " ");

  const inicio = DateTime
    .fromISO(horario.startTime)
    .setZone("America/Santiago")
    .setLocale("es");

  const fechaFormateada = inicio.toFormat(
    "cccc d 'de' LLLL 'a las' HH:mm"
  );

  return `Perfecto, ${datos.nombreTutor}. La solicitud para el ${servicioVisible} de ${datos.nombreMascota} quedó confirmada como simulación para el ${fechaFormateada}.

Esta demo no genera una reserva real, no bloquea horarios y no registra información en la clínica.

